            $candidateexamresultdate = Candidateexamresultdate::where('exam_id', $c["exam_id"])->where('candidate_id', $c["candidate_id"])->first();

            if(is_null($candidateexamresultdate)) {
                Candidateexamresultdate::create([
                    "exam_id" => $c["exam_id"],
                    "candidate_id" => $c["candidate_id"],
                    "underreview_status" => $c["underreview_status"],
                    "underreview_remarks" => $c["underreview_remarks"],
                    "withheld_status" => 0,
                    "withheld_remarks" => null,
                    "specialcase_status" => 0,
                    "specialcase_remarks" => null,
                    "publish_status" => 1,
                ]);
            }
            else {
                $candidateexamresultdate->update([
                    "underreview_status" => $c["underreview_status"],
                    "underreview_remarks" => $c["underreview_remarks"],
                    "withheld_status" => 0,
                    "withheld_remarks" => null,
                    "specialcase_status" => 0,
                    "specialcase_remarks" => null,
                    "publish_status" => 1,
                ]);
            }
            /*
            if(is_null($candidateexamresultdate)) {
                Candidateexamresultdate::create([
                    "exam_id" => $c["exam_id"],
                    "candidate_id" => $c["candidate_id"],
                    "underreview_status" => 1,
                    "underreview_remarks" => $c["underreview_remarks"],
                    "publish_status" > 1
                ]);
            }
            else {
                $candidateexamresultdate->update([
                    "underreview_status" => 1,
                    "underreview_remarks" => $c["underreview_remarks"],
                    "publish_status" > 1
                ]);
            }

            */

            unset($c);
        }
        unset($collections);
    }
}
